   ```cpp
   std::unordered_set<T*> allocated_ptrs_;  // Track all allocations

   T* allocate() {
       T* ptr = /* ... */;
       allocated_ptrs_.insert(ptr);
       return ptr;
   }
   ```

3. **Valgrind/AddressSanitizer:**
   ```bash
   g++ -fsanitize=address program.cpp
   ./a.out  # Reports leaks
   ```

