#include <iostream>

template<typename T>
class MemoryPool {
    char* memory_;
    T* free_list_;
    size_t capacity_;

public:
    MemoryPool(size_t size) : capacity_(size) {
        memory_ = new char[sizeof(T) * size];
        free_list_ = nullptr;

        // Bug: not initializing free list!
    }

    T* allocate() {
        if (!free_list_) {
            throw std::bad_alloc();
        }

        T* result = free_list_;
        free_list_ = *reinterpret_cast<T**>(free_list_);
        return result;
    }

    ~MemoryPool() {
        delete[] memory_;
    }
};

int main() {
    MemoryPool<int> pool(5);
    int* ptr = pool.allocate();  // Bug: what happens?
}

