int main() {
    {
        MemoryPool<std::string> pool(10);

        std::string* s1 = pool.allocate();
        new (s1) std::string("Hello");

        std::string* s2 = pool.allocate();
        new (s2) std::string("World");

        // Only destroy s1
        s1->~string();
