template<typename T>
class BoundedQueue {
private:
    std::queue<T> queue_;
    const size_t capacity_;

    std::mutex mutex_;
    std::condition_variable not_full_, not_empty_;

    // Statistics (protected by same mutex)
    size_t total_pushed_ = 0;
    size_t total_popped_ = 0;
    size_t max_size_reached_ = 0;

public:
    void push(const T& value) {
        std::unique_lock<std::mutex> lock(mutex_);
        not_full_.wait(lock, [this]() { return queue_.size() < capacity_; });

        queue_.push(value);
        ++total_pushed_;  // Update stat

        if (queue_.size() > max_size_reached_) {
            max_size_reached_ = queue_.size();
        }

        not_empty_.notify_one();
    }

    T pop() {
        std::unique_lock<std::mutex> lock(mutex_);
        not_empty_.wait(lock, [this]() { return !queue_.empty(); });

        T value = std::move(queue_.front());
        queue_.pop();
        ++total_popped_;  // Update stat

        not_full_.notify_one();
        return value;
    }

    struct Stats {
        size_t total_pushed;
        size_t total_popped;
        size_t max_size_reached;
        size_t current_size;
    };

    Stats get_stats() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return Stats{
            total_pushed_,
            total_popped_,
            max_size_reached_,
            queue_.size()
        };
    }
};

