    data_[index].~T();

    // Shift elements left
    for (size_t i = index; i < size_ - 1; ++i) {
        new (data_ + i) T(std::move(data_[i + 1]));
        data_[i + 1].~T();
    }

    --size_;

    return begin() + index;
}

