    bool pop(T& item) {
        // ... check empty ...

        T* slot = reinterpret_cast<T*>(&buffer_[current_head * sizeof(T)]);
        item = std::move(*slot);
        slot->~T();  // Explicit destructor

        // ...
    }
};
