    access_page(2, "Page 2 content");  // MISS
    access_page(3, "Page 3 content");  // MISS
    access_page(1, "");  // HIT
    access_page(4, "Page 4 content");  // MISS (evicts page 2)
    access_page(2, "");  // MISS (page 2 was evicted)

    return 0;
}

